    if m == 1 { 31 }
    else if m == 2 { 28 }
    else if m == 3 { 31 }
    else if m == 4 { 30 }
    else if m == 5 { 31 }
    else if m == 6 { 30 }
    else if m == 7 { 31 }
    else if m == 8 { 31 }
    else if m == 9 { 30 }
    else if m == 10 { 31 }
    else if m == 11 { 30 }
    else { 31 };

fn day_of_year(month: i64, day: i64) -> i64 = {
    let mut total: i64 = 0;
    for m in 1..month {
        total = total + days_in_month(m)
    };
    total + day
};

